// Validate and shape an outbound Dispatch request. Envelope:
//   {
//     operation: 'assign_driver' | 'update_status' | 'generic',
//     path:      '/api/v1/assignments'    // required for generic
//     method:    'POST'|'GET'|'PUT',
//     body:      {...},
//     correlation_id: '...',
//     _retry_count: 0
//   }
const kafkaMessage = $input.item.json;
const msg = typeof kafkaMessage.value === 'string' ? JSON.parse(kafkaMessage.value) : kafkaMessage.value;
if (!msg || !msg.operation) throw new Error('invalid dispatch-out message: missing operation');

const baseUrl = $env.DISPATCH_API_URL;
const apiKey  = $env.DISPATCH_API_KEY;
if (!baseUrl || baseUrl === 'CHANGE_ME')  throw new Error('DISPATCH_API_URL not configured');
if (!apiKey  || apiKey  === 'CHANGE_ME')  throw new Error('DISPATCH_API_KEY not configured');

const OPS = {
  assign_driver: { method: 'POST', path: '/api/v1/assignments' },
  update_status: { method: 'PATCH', path: `/api/v1/assignments/${msg.body?.assignment_id || ''}` },
  generic:       { method: msg.method || 'POST', path: msg.path || '' }
};
const op = OPS[msg.operation];
if (!op) throw new Error(`unsupported dispatch operation: ${msg.operation}`);
if (msg.operation === 'generic' && !op.path) throw new Error('generic requires path');
if (msg.operation === 'update_status' && !msg.body?.assignment_id) throw new Error('update_status requires body.assignment_id');

return {
  json: {
    url:            `${baseUrl}${op.path}`,
    method:         op.method,
    body:           msg.body || {},
    correlation_id: msg.correlation_id || $execution.id,
    retry_count:    msg._retry_count || 0,
    max_retries:    5,
    operation:      msg.operation,
    original:       msg,
    _apiKey:        apiKey
  }
};

const resp = $input.item.json;
const ctx  = $('Validate + Resolve').item.json;
return { json: {
  success: true,
  workflow: 'dispatch-outbound',
  operation: ctx.operation,
  correlation_id: ctx.correlation_id,
  response: resp,
  timestamp: new Date().toISOString()
}};

const error = $input.item.json;
const ctx = ($('Validate + Resolve').item || {}).json || {};
const retryCount = ctx.retry_count || 0;
const maxRetries = ctx.max_retries || 5;
const status = error.status || error.statusCode || (error.response && error.response.status) || 0;
const isTransient = status === 429 || (status >= 500 && status < 600);
const shouldRetry = isTransient && retryCount < maxRetries;
return { json: {
  workflow: 'dispatch-outbound',
  operation: ctx.operation,
  correlation_id: ctx.correlation_id,
  error_message: error.message || 'unknown error',
  status,
  retry_count: retryCount,
  max_retries: maxRetries,
  should_retry: shouldRetry,
  retry_delay_ms: Math.min(60000, 1000 * Math.pow(2, retryCount)) + Math.floor(Math.random() * 500),
  requeue_payload: { ...(ctx.original || {}), _retry_count: retryCount + 1 },
  timestamp: new Date().toISOString()
}};
